queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?section_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSections ?child ; p:hasNewspapers ?parent . } GROUP BY ?child }
  ?child p:section_name ?section_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Newspapers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?newspaper_name ?section_name WHERE {
  ?newspapers_sections a :Newspapers_Sections .
  ?sections a :Sections .
  ?newspapers_sections p:hasSections ?sections .
  ?newspapers a :Newspapers .
  ?newspapers_sections p:hasNewspapers ?newspapers .
  ?newspapers p:newspaper_name ?newspaper_name .
  ?sections p:section_name ?section_name .
} }
  collective: { SELECT ?section_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSections ?child ; p:hasNewspapers ?parent . } GROUP BY ?child }
  ?child p:section_name ?section_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Newspapers } }
  FILTER(?nf = ?total)
} }
}
